const dao = {
  id: 'dao',
  title: 'DAOs & Governance',
  emoji: '🏛',
  color: '#7C3AED',
  gradient: ['#5B21B6', '#7C3AED'],
  description: 'Understand, participate in, and build decentralized autonomous organizations.',
  category: 'Governance',
  modules: [
    {
      id: 'dao_beg',
      level: 'beginner',
      title: 'DAO Fundamentals',
      emoji: '🗳',
      description: 'What DAOs are, how they govern protocols, and how to participate in them.',
      color: '#7C3AED',
      lessons: [
        { id: 'dao_beg_l1', title: 'What is a DAO?', slides: [
          { type: 'intro', title: 'Organization Without a CEO', body: 'A Decentralized Autonomous Organization (DAO) is an organization governed by smart contracts and its token holders — without traditional management hierarchy. Rules are code; governance is transparent; membership is open to anyone holding the governance token.' },
          { type: 'text', title: 'The First DAO', body: '"The DAO" launched in April 2016 on Ethereum — raised $150M (largest crowdfund ever at the time) in 28 days. A smart contract vulnerability was exploited, draining $60M. Ethereum hard-forked to reverse the hack — creating the ETH/ETC split. Despite the failure, it proved the concept and launched the DAO era.' },
          { type: 'text', title: 'Types of DAOs', body: 'Protocol DAOs: govern DeFi protocols (Uniswap, Aave, Compound). Social DAOs: membership communities (Friends With Benefits, BanklessDAO). Investment DAOs: collectively invest capital (MetaCartel Ventures, FlamingoDAO). Service DAOs: coordinate work (Raid Guild, dOrg). Collector DAOs: buy NFTs together (PleasrDAO bought the Wu-Tang album). Each has different governance needs and token models.' },
          { type: 'highlight', title: 'How Decisions Get Made', body: 'Proposal → Forum discussion (1-2 weeks) → On-chain vote (tokenholders vote yes/no/abstain) → Timelock (48-72 hours for security) → Execution. The whole process is public, auditable, and verifiable. No closed boardrooms. No hidden agendas. The downside: slow, contentious, and vulnerable to whale dominance.' },
          { type: 'text', title: 'Token-Based Voting', body: '1 token = 1 vote in most DAOs. This creates plutocracy risk: Andreessen Horowitz (a16z) alone holds enough UNI to veto most Uniswap proposals. Alternatives: quadratic voting (diminishing returns for large holders), reputation-based voting (non-transferable), conviction voting (votes accumulate over time). No perfect system — each trades off efficiency against decentralization.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'DAOs are code-governed organizations with public, transparent decision-making. Types include protocol, social, investment, service, and collector DAOs. Token-based voting is the norm but creates plutocracy risk — no perfect governance system yet exists.' },
        ]},
        { id: 'dao_beg_l2', title: 'Major DAOs Today', slides: [
          { type: 'intro', title: 'The $10B Treasury Landscape', body: 'Combined DAO treasuries exceed $10B in assets. Understanding the major DAOs shows how radically different each is — from multi-billion DeFi protocols to 100-person creative collectives, the DAO umbrella covers a wide range of organizational models.' },
          { type: 'text', title: 'Uniswap DAO', body: 'UNI token holders govern the world\'s largest DEX. Uniswap treasury: ~$2B in UNI. Key decisions: fee switch (should protocol fees flow to UNI holders vs. LPs?), cross-chain deployments, grant programs. The fee switch debate has lasted 2+ years without resolution — demonstrating both the power and challenge of decentralized governance at scale.' },
          { type: 'text', title: 'MakerDAO / Sky', body: 'MakerDAO governance controls the DAI stablecoin ($5B+ supply). MKR holders vote on collateral types, stability fees, and risk parameters. A bad governance vote could destabilize DAI — governance has real, immediate financial consequences. MakerDAO has evolved into "Sky" with more sophisticated governance structures, reflecting the challenges of governing a critical financial protocol.' },
          { type: 'highlight', title: 'BanklessDAO', body: 'BanklessDAO is a media and community DAO founded in 2021 after the Bankless podcast launched a governance token. 15,000+ members coordinate to create educational content, run bounty programs, launch guilds (design, dev, writers). No central authority — each guild self-manages. The chaos is also the point: distributed creation with minimal coordination costs.' },
          { type: 'text', title: 'PleasrDAO: Collector DAOs', body: 'PleasrDAO formed to buy the Uniswap v3 banner painting, then acquired: the one-of-one Wu-Tang album (previously owned by Martin Shkreli, seized by DOJ), Edward Snowden\'s "Stay Free" NFT, Doge meme original. Collector DAOs demonstrate how pooled crypto capital can acquire cultural artifacts previously inaccessible to any individual. $180M+ in assets collectively owned.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Uniswap DAO controls $2B with real governance deadlock examples. MakerDAO governance directly impacts financial stability. BanklessDAO shows creative coordination. PleasrDAO shows collector DAOs pooling capital for cultural acquisitions.' },
        ]},
        { id: 'dao_beg_l3', title: 'Participating in Governance', slides: [
          { type: 'intro', title: 'Your Vote Matters', body: 'Most DAO token holders never vote — typical governance participation is 5-15% of eligible tokens. This means a relatively small amount of active participation can have outsized influence. The barrier isn\'t technical — it\'s time, attention, and information. This lesson removes the information barrier.' },
          { type: 'text', title: 'Finding Proposals', body: 'Snapshot.org: off-chain voting hub for most DAOs (gas-free). Tally.xyz: on-chain governance dashboard. Commonwealth.im: forum and governance portal. Each major protocol has its own forum (forum.compound.finance, gov.uniswap.org). The workflow: follow the forum, read proposals when posted, discuss in forum comments, vote on Snapshot or Tally when the vote opens.' },
          { type: 'text', title: 'Evaluating Proposals', body: 'Key questions: Does this proposal match the DAO\'s stated mission? Who benefits and who pays? Are the financial projections realistic? Is this irreversible (smart contract upgrade) or reversible (spending proposal)? Who is behind the proposal — what\'s their track record? Beware proposals that benefit a specific party disproportionately or were written by the same party that benefits.' },
          { type: 'highlight', title: 'Delegation', body: 'If you hold governance tokens but don\'t want to evaluate every proposal: delegate your votes to an active, knowledgeable delegate. Most DAOs have delegate registries (Uniswap delegate hub, Compound governance) where delegates publish their platforms and voting history. Delegation takes 2 minutes; your votes go to someone who is actively engaged. This is how governance participation scales.' },
          { type: 'text', title: 'Contributing Beyond Voting', body: 'The most impactful governance participation: write the proposals others vote on. Analyze spending and report to the community. Call out governance attacks before they execute. Contribute to working groups. BanklessDAO\'s most valuable contributors aren\'t the richest token holders — they\'re the people who show up consistently, write quality content, and help new members.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Governance participation is 5-15% typically — your vote has outsized influence. Use Snapshot, Tally, and protocol forums. Evaluate proposals critically. Delegate if you lack time to evaluate. Contributing to proposals and working groups is more impactful than voting alone.' },
        ]},
        { id: 'dao_beg_l4', title: 'DAO Tooling', slides: [
          { type: 'intro', title: 'The DAO Technology Stack', body: 'Running a DAO requires coordination infrastructure: voting systems, treasury management, contributor payments, communication channels, and proposal frameworks. The tooling ecosystem has matured significantly since 2020.' },
          { type: 'text', title: 'Voting Infrastructure', body: 'Snapshot: gasless off-chain voting. Millions of votes happen here daily. Supports multiple voting types (single choice, approval, weighted, quadratic). Tally: on-chain voting with real execution (votes actually trigger smart contract changes). Boardroom: governance analytics and unified dashboard across DAOs. Gnosis SafeSnap: connects Snapshot votes to Gnosis Safe treasury execution.' },
          { type: 'text', title: 'Treasury Management', body: 'Gnosis Safe: multi-signature wallet used by 90%+ of major DAOs. Requires M-of-N signatures to execute transactions. Multisig composition matters: Uniswap treasury requires 4-of-7 signers. Llama: treasury analytics and spending dashboards. Parcel: payroll and mass payment tool for contributor payments in crypto. OpenZeppelin Defender: automates treasury operations within governance-approved parameters.' },
          { type: 'highlight', title: 'Communication Tools', body: 'Discord: day-to-day community coordination. Discourse/Commonwealth: structured governance discussion forums. Notion: documentation and knowledge base. Coordinape: peer-to-peer contribution recognition and payment. Mirror: publishing DAO research and governance updates as NFTs. The combination of Discord (fast, informal) + Discourse (structured, searchable) + Mirror (published, permanent) creates a layered communication stack.' },
          { type: 'text', title: 'Working Groups and Guilds', body: 'Mature DAOs organize work into working groups (SubDAOs, guilds, committees). Compound\'s Grants Committee, Uniswap\'s Bridge Assessment Committee, BanklessDAO\'s guilds. Working groups have mandate, budget, and accountability back to the main DAO. This allows specialization without losing the DAO\'s decentralized nature — working groups execute; the DAO ratifies their budgets and mandates.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Snapshot (gasless voting) + Tally (on-chain execution) + Gnosis Safe (multisig treasury) + Discourse (structured forums) form the core DAO stack. Working groups enable specialization within decentralized governance.' },
        ]},
        { id: 'dao_beg_l5', title: 'DAO Careers', slides: [
          { type: 'intro', title: 'Working in DAOs', body: 'DAOs have created entirely new career paths — contributors who work for multiple DAOs simultaneously, specialists who write governance proposals, researchers who analyze protocol data, and community managers who build culture. This distributed work model is the future of crypto employment.' },
          { type: 'text', title: 'Contributor Models', body: 'Bounties: one-time paid tasks posted publicly. Applied to and completed by community members. Part-time contributors: recurring stipends for regular contributions (20h/week). Full-time: formal employment equivalent, salary + token allocation, benefits. Core team: essentially employees, even in "decentralized" DAOs. Most successful DAO contributors start with bounties and earn their way into recurring roles.' },
          { type: 'text', title: 'What DAOs Pay For', body: 'Development (Solidity, frontend). Writing and content creation. Research and analytics. Business development and partnerships. Community management. Legal and compliance. Design (UI/UX, branding). Grant program management. Protocol security and auditing. Treasury management. Every function of a company exists in DAOs — just distributed across community contributors rather than employees.' },
          { type: 'highlight', title: 'Finding DAO Work', body: 'DeWork.xyz: DAO job board and bounty platform. Layer3.xyz: skill-building tasks with crypto rewards. Gitcoin: grants and bounties for open source. Individual DAO Discord servers: most have a #contribute or #bounties channel. Starting with small bounties in a DAO you already participate in as a community member is the most reliable path to paid contributor status.' },
          { type: 'text', title: 'Building a DAO Portfolio', body: 'Document every contribution publicly: completed proposals with votes, code commits, published research, community events organized. Create a "contributor portfolio" on Mirror or Notion that links to your on-chain contributions. DAO hiring is reputation-based — your public track record of governance participation, proposal writing, and delivered work is your resume in the DAO world.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'DAO career paths: bounties → part-time → full-time contributor. Platforms: DeWork, Layer3, Gitcoin. Every company function exists in DAOs. Build a public contributor portfolio on Mirror or Notion. On-chain track record is your crypto resume.' },
        ]},
      ],
      quiz: [
        { id: 'dao_beg_q1', question: 'What was the outcome of "The DAO" hack in 2016 and its significance?', options: ['The DAO was successfully recovered and relaunched', 'A $60M exploit was executed via a smart contract vulnerability, leading to Ethereum\'s hard fork and the ETH/ETC split — while proving the DAO concept was real enough to attract $150M', 'The hack was prevented by the Ethereum community before funds were lost', 'The DAO hack resulted in smart contract regulation in the US'], correct: 1, explanation: 'The DAO raised $150M (then the largest crowdfund ever), was hacked for $60M via reentrancy, and Ethereum hard-forked to reverse it. This created ETH (reversed) and ETC (unchanged), the most consequential schism in Ethereum history. Despite the failure, it proved DAOs could attract massive capital and coordination.' },
        { id: 'dao_beg_q2', question: 'What is governance delegation and why is it important?', options: ['Delegating treasury management to a multisig', 'Assigning your voting power to an active, knowledgeable delegate so your tokens participate in governance even when you can\'t evaluate every proposal — scaling participation beyond active holders', 'Delegating smart contract upgrades to developers', 'Giving governance tokens to new community members'], correct: 1, explanation: 'Most token holders can\'t evaluate every governance proposal. Delegation lets you assign your votes to someone who actively researches and votes. This scales governance participation — instead of 5% voter turnout, effective delegation can represent 30-40% of supply in informed decisions.' },
        { id: 'dao_beg_q3', question: 'What is Snapshot used for in DAO governance?', options: ['Taking snapshots of protocol TVL for audits', 'Gasless off-chain voting — token holders vote without paying gas fees, making participation accessible to all holders regardless of ETH balance', 'Creating smart contract snapshots for upgrades', 'Token distribution snapshots for airdrops'], correct: 1, explanation: 'On-chain voting requires gas for each vote — economically prohibitive for small holders. Snapshot enables gasless off-chain voting by verifying token balances at a specific block without requiring a transaction. Most DAOs use Snapshot for routine governance and Tally for on-chain execution of major decisions.' },
        { id: 'dao_beg_q4', question: 'What did PleasrDAO do that demonstrated the power of collector DAOs?', options: ['Built a major DeFi protocol', 'Pooled member capital to collectively acquire high-value cultural assets impossible for individuals, including the one-of-a-kind Wu-Tang album', 'Launched the first DAO-governed stablecoin', 'Created the first DAO governance standard'], correct: 1, explanation: 'PleasrDAO pooled crypto capital to buy assets no individual could: the sole Wu-Tang album (DOJ-seized from Martin Shkreli), Edward Snowden\'s "Stay Free" NFT, and the original Doge meme. Collective ownership of unique cultural artifacts — $180M+ in assets — demonstrates DAOs as investment vehicles beyond financial protocols.' },
        { id: 'dao_beg_q5', question: 'What is the best starting path for building a DAO career?', options: ['Buy the maximum amount of governance tokens immediately', 'Start with bounties in a DAO you already participate in as a community member — complete tasks reliably, build reputation, advance to recurring contributor roles', 'Apply directly for full-time DAO employment positions', 'Create a new DAO in your area of expertise'], correct: 1, explanation: 'DAO hiring is reputation-based. Completing bounties publicly demonstrates skill and reliability. Consistent participation in community discussion builds relationships. This track record becomes your resume — leading to recurring contributor roles and eventually full-time status. Buying tokens gives voting rights, not employment status.' },
      ],
    },
    {
      id: 'dao_int',
      level: 'intermediate',
      title: 'DAO Operations',
      emoji: '⚙️',
      description: 'Run treasury, coordinate contributors, and scale DAO operations effectively.',
      color: '#7C3AED',
      lessons: [
        { id: 'dao_int_l1', title: 'Treasury Management', slides: [
          { type: 'intro', title: 'Stewarding Billions', body: 'DAO treasuries collectively hold $10B+. Most of this is in native tokens that can lose 90% of value in a bear market. Effective treasury management — diversification, financial planning, runway extension — is a critical and often neglected DAO function.' },
          { type: 'text', title: 'The Diversification Problem', body: 'Uniswap treasury is 99%+ UNI tokens. If UNI crashes 90%, the treasury crashes 90%. Most protocol DAOs face this — their treasury is denominated in their own token. The 2022 bear market wiped out years of runway from dozens of DAOs whose treasuries went from $500M to $20M. Diversifying into stablecoins and ETH is the first priority of treasury management.' },
          { type: 'text', title: 'Diversification Strategies', body: 'Options for treasury diversification: OTC sales (sell tokens to strategic investors quietly, avoiding market impact). Streaming payment protocols (Sablier, Superfluid: gradually stream token sales, averaging the price over time). LBP (Liquidity Bootstrapping Pool): gradually sell tokens via Balancer LBP. Each approach has different market impact, legal considerations, and timing constraints.' },
          { type: 'highlight', title: 'Treasury DeFi Deployment', body: 'Idle treasury earns nothing. Best practices: stablecoin portion → Aave/Compound for 3-5% yield. ETH portion → Lido staking for ~3.5% yield. Token portion → liquidity provision on Uniswap (earns fees). MakerDAO allocates billions in RWAs for 5%+ yield. A $100M treasury earning 4% = $4M/year in additional runway — the equivalent of hiring 40 developers.' },
          { type: 'text', title: 'Budget Process and Oversight', body: 'Working groups submit quarterly budget proposals. DAO votes on each. An independent "treasury watchdog" committee monitors spending. Public dashboards (Dune, Llama) display treasury balance and spending in real-time. Monthly treasury reports published on Mirror or governance forum. Transparency is non-negotiable — any treasury spend the community can\'t see creates trust deficit.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'DAO treasuries face concentration risk in native tokens. Diversify into stablecoins + ETH through OTC or streaming. Deploy idle treasury via DeFi for 3-5% yield. Maintain public spending dashboards and monthly reports. Transparency = trust.' },
        ]},
        { id: 'dao_int_l2', title: 'Contributor Compensation', slides: [
          { type: 'intro', title: 'Paying a Distributed Workforce', body: 'DAOs pay contributors in dozens of countries in tokens and stablecoins — no W2s, no HR department, no benefits administration. Building compensation systems that are fair, transparent, and motivating across global contexts is one of the hardest operational challenges in DAOs.' },
          { type: 'text', title: 'Compensation Models', body: 'Fixed stipends: X USDC/month for Y deliverables. Simple, predictable. Variable rewards: post-contribution Coordinape rounds (peers allocate tokens to each other based on perceived contribution). Retroactive public goods funding (Optimism\'s RetroPGF): grants awarded after value is created and visible. Each model attracts different contributor types and creates different incentive dynamics.' },
          { type: 'text', title: 'Coordinape: Peer Rewards', slides: [], body: 'Coordinape allows contributors to distribute GIVE tokens to teammates each epoch. At epoch end, GIVE converts to DAO token allocation proportional to received GIVE. Result: peers reward each other rather than a central committee deciding. Benefits: surfaces hidden contributions managers miss. Risk: popularity contests, cliques, reciprocal GIVE exchanges that game the system.' },
          { type: 'highlight', title: 'Retroactive Public Goods Funding', body: 'Optimism\'s RetroPGF program has distributed tens of millions in OP tokens to projects that created value for the Ethereum ecosystem — retroactively, after the value is clear. Round 1: $1M. Round 3: $90M across 500+ projects. The principle: it\'s easier to agree that value was created than to predict it will be. Applied inside DAOs: reward contributors after their contributions prove valuable.' },
          { type: 'text', title: 'Tax and Legal Reality', body: 'DAO token income is taxable in most jurisdictions. Contributors receive 1099s (US) or equivalent. DAO payments in tokens are taxed at fair market value at receipt. SAFT (Simple Agreement for Future Tokens): a legal structure for token compensation that delays taxation. LexDAO provides legal templates for DAO contributor agreements. Ignoring the legal reality creates individual liability risk for contributors.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Fixed stipends, Coordinape peer rewards, and RetroPGF represent different compensation philosophies. Coordinape scales peer recognition but risks gaming. RetroPGF rewards proven value. All DAO token income is taxable — legal structure matters for contributor protection.' },
        ]},
        { id: 'dao_int_l3', title: 'Governance Attack Vectors', slides: [
          { type: 'intro', title: 'When Governance Becomes a Weapon', body: 'Governance systems are attack surfaces. Understanding how governance can be weaponized allows DAO designers and participants to recognize attacks before they execute and defend against them.' },
          { type: 'text', title: 'Flash Loan Governance Attacks', body: 'The Beanstalk exploit (April 2022): attacker borrowed $1B via flash loan. Acquired 79% of governance tokens temporarily. Proposed and passed a malicious governance proposal. Drained $182M. Repaid flash loan. All in one transaction. The fix: time-locked governance (proposals require stake held for multiple blocks — flash loans can\'t hold tokens across multiple blocks).' },
          { type: 'text', title: 'Whale Plutocracy', body: 'A16z holds enough UNI to significantly influence Uniswap votes. Paradigm has similar power over multiple protocol DAOs. Whales can vote down unfavorable proposals, extract value for themselves, or stall governance entirely. The problem: venture capital funds own large governance stakes from early investments. Quadratic voting and liquid democracy are proposed mitigations — neither widely adopted.' },
          { type: 'highlight', title: 'Governance Deadlock', body: 'Uniswap\'s fee switch debate: should protocol fees flow to UNI holders? It\'s been discussed since 2021. As of 2024, still not activated. Reasons: legal risk, LP incentive disruption, whale disagreement. Deadlock is governance failure — it means the DAO cannot make a decision even when the community majority wants it. It demonstrates the real cost of fully decentralized governance.' },
          { type: 'text', title: 'Social Engineering Attacks', body: 'More subtle than flash loans: a well-funded attacker gradually accumulates governance tokens over months. Builds reputation in the community. Gets elected to important committees. Then uses committee power to make favorable parameter changes or extract value via "legitimate" governance proposals. Defense: proposal authors\' track records matter. Off-chain reputation + on-chain history before major committee appointments.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Flash loan attacks require time-locked governance. Whale plutocracy is structural — quadratic voting partially mitigates. Governance deadlock is a real failure mode. Social engineering is the slow, hard-to-detect attack. Defense: robust proposal review, committee vetting, and governance parameter safeguards.' },
        ]},
        { id: 'dao_int_l4', title: 'DAO Legal Structures', slides: [
          { type: 'intro', title: 'The Liability Gap', body: 'Most DAOs operate as unincorporated associations — legally ambiguous entities where every token holder may be personally liable for DAO actions and debts. The Ooki DAO CFTC lawsuit (2022) named "token holders" as defendants. This is the single largest legal risk facing DAO participants.' },
          { type: 'text', title: 'Wyoming DAO LLC', body: 'Wyoming was the first US state to recognize DAOs as legal entities (2021). A Wyoming DAO LLC is a legal entity that: limits member liability, can sign contracts, can hold property, can sue and be sued. Major caveat: DAO LLC members are anonymous to the public but must have a registered agent and comply with Wyoming law. Suitable for smaller, US-focused DAOs.' },
          { type: 'text', title: 'Cayman Foundation', body: 'Cayman Islands Foundation Companies are the most common legal structure for major DeFi protocols. The Foundation: can hold treasury assets legally, has directors who take legal responsibility, provides liability shield for token holders, is tax-neutral (no Cayman entity-level tax). Uniswap, Aave, and Compound all use Foundation structures. Cost: $50k-$150k annually in legal + administration fees.' },
          { type: 'highlight', title: 'Marshall Islands DAO Act', body: 'The Marshall Islands recognized DAOs as legal entities in 2022 — with lighter requirements than Wyoming and Cayman. Full DAO governance over legal entity decisions. Non-profit and profit variants available. Attractive for truly decentralized DAOs that want legal personhood without heavy traditional corporate requirements.' },
          { type: 'text', title: 'The Unincorporated Reality', body: 'Many DAOs still operate without legal structure — particularly DeFi protocols that value maximal decentralization. Risk: CFTC, SEC, or other regulator could name token holders as defendants. Mitigation: minimize US-facing activity, distribute governance maximally, avoid any centralized control points. This is the "regulatory arbitrage" approach that regulators are increasingly challenging.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Unincorporated DAOs expose token holders to personal liability. Wyoming DAO LLC, Cayman Foundation, and Marshall Islands DAO Act provide legal personhood with liability shields. The right structure depends on jurisdiction, scale, and decentralization philosophy.' },
        ]},
        { id: 'dao_int_l5', title: 'Cross-DAO Collaboration', slides: [
          { type: 'intro', title: 'Ecosystem Coordination', body: 'DAOs don\'t exist in isolation — the DeFi ecosystem is a web of interdependencies. Aave and Maker both hold ETH collateral. Uniswap pools underlie most DeFi pricing. DAOs must collaborate as much as they compete, and the patterns for this collaboration are still emerging.' },
          { type: 'text', title: 'Protocol-to-Protocol Collaboration', body: 'Examples of successful cross-DAO collaboration: Maker + Aave: Aave integrates DAI as a lending asset → more DAI demand → better DAI stability. Curve + Convex: Convex aggregates CRV, Curve benefits from deeper liquidity and more veCRV. Lido + multiple DeFi protocols: stETH integration across Aave, Compound, Curve. Each integration creates mutual dependency that sustains both protocols.' },
          { type: 'text', title: 'Grants Coordination', body: 'Ecosystem grants programs: Ethereum Foundation funds core infrastructure. Optimism RetroPGF funds ecosystem projects. Arbitrum grants program. Uniswap Grants Program. These programs avoid duplicate funding through coordination forums. The Grants Cartography project maps all major crypto grant programs to identify gaps and overlaps.' },
          { type: 'highlight', title: 'Meta-Governance', body: 'Meta-governance: holding governance tokens of one protocol to vote in another protocol\'s governance. Yearn holds COMP and AAVE tokens and votes in those protocols\' governance to benefit Yearn vaults. A16z uses Uniswap governance votes to influence outcomes that affect their portfolio companies. Meta-governance is an underexplored but powerful coordination mechanism.' },
          { type: 'text', title: 'The Interoperability Layer', body: 'Future DAO coordination requires: standardized governance interfaces (so DAOs can vote in each other\'s governance programmatically), shared security frameworks, and cross-DAO treasury management standards. The DAOhaus and OpenZeppelin Governor contracts are steps toward this. A true "internet of DAOs" — where governance coordination is as seamless as DeFi composability — is the long-term vision.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'Protocol integrations create positive-sum dependencies. Grants programs coordinate through cartography to avoid duplication. Meta-governance lets DAOs vote in each other\'s governance. The future is an "internet of DAOs" with standardized governance interfaces.' },
        ]},
      ],
      quiz: [
        { id: 'dao_int_q1', question: 'Why is most DAO treasury concentration in native tokens a serious risk?', options: ['Native tokens have high gas fees for treasury management', 'If the native token crashes 90% in a bear market, the treasury crashes 90% too — eliminating development runway. 2022 saw dozens of DAOs go from $500M to $20M treasuries overnight', 'Native tokens can\'t be used for treasury payments', 'Regulatory requirements prohibit native token concentration'], correct: 1, explanation: 'Treasury in native tokens = concentrated single-asset exposure to your own token. In 2022, BTC/ETH crashed 70%+ and most native tokens 90%+. DAOs with only native tokens in treasury suddenly had months instead of years of runway. Diversification into stablecoins and ETH is the #1 treasury management priority.' },
        { id: 'dao_int_q2', question: 'How does the Beanstalk governance attack work?', options: ['By gradually accumulating tokens over months and bribing validators', 'Flash loan borrows enough governance tokens for a supermajority in one block, passes a malicious proposal instantly (no timelock existed), drains the treasury, repays the flash loan — all atomically', 'By exploiting a smart contract vulnerability in the governance contract', 'By submitting thousands of small proposals to overwhelm governance voters'], correct: 1, explanation: 'Flash loan governance: borrow $1B → acquire 79% governance tokens temporarily → propose + pass malicious vote (no timelock) → drain $182M → repay loan. The fix: vote-escrowed governance tokens can\'t be flash-loaned since they require time commitments. Timelocks also allow token holders to react before execution.' },
        { id: 'dao_int_q3', question: 'What is Retroactive Public Goods Funding (RetroPGF)?', options: ['A grant program that predicts future valuable projects', 'Awarding grants after value is demonstrably created — making it easier to agree on what was valuable retrospectively than to predict in advance. Optimism has distributed tens of millions in OP tokens via RetroPGF', 'Refunding failed governance proposals', 'A tax rebate for DAO contributors'], correct: 1, explanation: 'Predicting which projects will create value is hard; recognizing value after the fact is easier. Optimism\'s RetroPGF has distributed $90M+ in Round 3 alone to projects that demonstrably contributed to the Ethereum ecosystem. It solves the VC prediction problem — reward what worked, not what might work.' },
        { id: 'dao_int_q4', question: 'What legal risk did the Ooki DAO CFTC lawsuit highlight for DAO participants?', options: ['DAOs must register as securities exchanges', 'Token holders of unincorporated DAOs may face personal liability — the CFTC named "token holders" as defendants, demonstrating that anonymous participation doesn\'t guarantee legal protection', 'DAO governance tokens are always classified as securities', 'DAOs must have physical offices in the US to operate'], correct: 1, explanation: 'The Ooki DAO case: CFTC sued the DAO itself and served process on token holders via governance forums. Without legal entity structure, every token holder can be personally liable for DAO obligations. This is why Wyoming DAO LLCs, Cayman Foundations, and Marshall Islands structures exist — to provide liability shields.' },
        { id: 'dao_int_q5', question: 'What is "meta-governance" in the context of DAO coordination?', options: ['Governance of the entire blockchain network', 'Holding governance tokens of one protocol to vote in that protocol\'s governance on behalf of your own protocol — allowing DAOs to coordinate and influence each other\'s decisions', 'A layer-2 governance aggregation system', 'Delegating all governance to a single committee'], correct: 1, explanation: 'Yearn Finance holds COMP and AAVE governance tokens, voting in those protocols to benefit Yearn\'s yield strategies. A16z uses UNI token voting power to influence Uniswap proposals that affect their portfolio companies. Meta-governance creates a web of DAO interdependency — the same dynamics as composability, but in governance.' },
      ],
    },
    {
      id: 'dao_exp',
      level: 'expert',
      title: 'Building a DAO',
      emoji: '🔨',
      description: 'Design governance systems, incentive structures, and coordination mechanisms for new DAOs.',
      color: '#7C3AED',
      lessons: [
        { id: 'dao_exp_l1', title: 'Governance Design Principles', slides: [
          { type: 'intro', title: 'Mechanism Design for Organizations', body: 'Designing a DAO governance system is applied mechanism design: creating rules where rational self-interested actors, following those rules, collectively produce good outcomes. Every governance parameter is a choice with tradeoffs — no system is optimal in all contexts.' },
          { type: 'text', title: 'The Governance Surface Area', body: 'What should require governance? Everything: slow, secure, community-decided. Nothing: fast iteration, team decided. Most DAOs exist on a spectrum. Progressive decentralization is the approach: start with multisig control, add governance voting over 2-4 years as trust is established. Uniswap launched with multisig control → added governance → is moving toward more immutability. This is the right arc.' },
          { type: 'text', title: 'Voting Power Design', body: 'Token-weighted (1 token = 1 vote): simple, plutocratic. Quadratic voting (cost = n² tokens to cast n votes): reduces whale advantage, but vulnerable to Sybil attacks. Conviction voting (votes accumulate over time): favors long-term holders, reduces vote buying. Time-weighted (longer holding = more votes): aligns with long-term holders. Each distributes power differently — choose based on your community structure.' },
          { type: 'highlight', title: 'Quorum and Supermajority', body: 'Quorum: minimum participation required. Too low = small group passes anything. Too high = governance deadlock. Uniswap: 40M UNI quorum (4% of supply). Compound: 400,000 COMP. Supermajority: should major decisions require >50%? Constitutional changes in traditional governments require 2/3 or 3/4. DAO equivalent: smart contract upgrades requiring 67%+ prevents simple majorities making irreversible changes.' },
          { type: 'text', title: 'The Governance Lifecycle', body: 'Temperature Check → Governance Forum Discussion → Snapshot Signal Vote → Full Governance Proposal → On-Chain Vote → Timelock → Execution. This lifecycle exists to: surface issues early (temp check), build consensus (forum), gauge support without gas (signal vote), and give holders time to respond before execution (timelock). Compressing these steps increases efficiency but reduces legitimacy.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Governance design is mechanism design. Progressive decentralization is the right arc. Voting power choices (quadratic, conviction, time-weighted) distribute power differently. Quorum thresholds balance participation vs deadlock. Full governance lifecycle builds legitimacy.' },
        ]},
        { id: 'dao_exp_l2', title: 'Tokenomics for DAOs', slides: [
          { type: 'intro', title: 'Token as Governance Infrastructure', body: 'DAO governance tokens are more than speculative assets — they\'re coordination mechanisms. How tokens are distributed determines who controls the protocol. How they\'re earned determines what behaviors the protocol incentivizes. The tokenomics design is the governance design.' },
          { type: 'text', title: 'Initial Token Distribution', body: 'Best practice: 40-50% community (retroactive airdrop + ongoing distribution). 20-25% team (4-year vest, 1-year cliff). 15-20% investors (2-4 year vest). 10-15% treasury (governed by DAO). Distributions weighted toward community maximize decentralization. VC-heavy distributions (investors getting 30%+) create concentrated control that undermines DAO legitimacy — the community sees through it immediately.' },
          { type: 'text', title: 'Vesting and Lock-ups', body: 'Team tokens: 4-year linear vest with 1-year cliff is the standard. Cliff prevents immediate dump if team leaves. 4-year align team with long-term. Investor tokens: 2-4 year vest (shorter than team is a red flag). Token unlock calendars are public (token.unlocks.app) — large unlocks create selling pressure that experienced traders front-run. Design vesting to avoid concentrated unlock events.' },
          { type: 'highlight', title: 'Ve-Tokenomics', body: 'Vote-escrow (ve) tokenomics (Curve\'s innovation): lock tokens for 1-4 years to receive veCRV. veCRV gets: boosted rewards (up to 2.5x), 50% of protocol fees, governance votes. Longer lock = more veCRV. This concentrates governance power in long-term aligned holders. Creates strong demand for tokens (must lock to get governance rights) while dramatically reducing sell pressure. The most successful tokenomics innovation in DeFi.' },
          { type: 'text', title: 'Emission Sustainability', body: 'Protocols often launch with high token emissions to attract liquidity and users. These must decrease over time as the protocol generates real revenue. Model: Year 1: 30% of supply emitted. Year 2: 20%. Year 3-4: 15%. Remaining distributed over 10+ years. Flat or increasing emissions = terminal inflation = token price → 0. The emission schedule is a promise to future holders — it must be credible.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Community-heavy token distribution maximizes legitimacy. Team: 4-year vest with 1-year cliff. Ve-tokenomics reduces sell pressure while aligning governance with long-term holders. Decreasing emission schedules signal protocol sustainability.' },
        ]},
        { id: 'dao_exp_l3', title: 'SubDAOs and Specialization', slides: [
          { type: 'intro', title: 'Scaling DAO Operations', body: 'Full DAO governance on every decision is impractical — decisions take weeks, voter fatigue is real, and specialists are more effective on narrow domains. SubDAOs (working groups, guilds, committees) solve this by delegating specific mandates to smaller, specialized groups with defined accountability.' },
          { type: 'text', title: 'Working Group Design', body: 'A working group needs: clear mandate (what they decide, what they can\'t). Budget (quarterly allocation voted by DAO). Accountability (monthly reporting, annual renewal votes). Term limits (2-year terms prevent entrenchment). Composition (minimum active contributors to prevent capture). DAO approves mandate + budget; working group executes within those bounds.' },
          { type: 'text', title: 'Nested Governance', body: 'Large DAOs use nested governance: Main DAO → approves mandates and quarterly budgets for → Working Groups → who may have Sub-Working Groups. Each level has appropriate authority and accountability. Compound\'s Grants Committee, Uniswap\'s Bridge Assessment Committee, and Aave\'s Risk Committee all operate this way. Specialization + accountability is the operating model.' },
          { type: 'highlight', title: 'The Lab Model', body: 'Many "decentralized" protocols use a Labs model: a company (Uniswap Labs, Aave Companies) develops the protocol while a DAO governs it. Labs does day-to-day development; DAO controls smart contract upgrades. This hybrid works well practically — Labs provides speed, DAO provides legitimacy and parameter control. Critics argue it\'s decentralization theater. Reality: it\'s pragmatic for early-stage protocols.' },
          { type: 'text', title: 'SubDAO Autonomy and Accountability', body: 'The tension: SubDAOs need enough autonomy to act efficiently, but enough accountability to prevent self-dealing. Best practices: multi-sig for SubDAO treasury (not single key). Quarterly budget reviews by full DAO. Public monthly reports (not just financial — work product too). Annual mandate renewal. Conflict of interest rules (no self-interested votes). The Optimism Foundation governance is the most developed example of SubDAO accountability structures.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'SubDAOs enable specialization at scale. Working groups need clear mandates, budgets, reporting requirements, and term limits. Nested governance delegates authority proportionally. The Labs + DAO hybrid is pragmatic for early-stage protocols. Accountability mechanisms prevent SubDAO capture.' },
        ]},
        { id: 'dao_exp_l4', title: 'Governance Incentives', slides: [
          { type: 'intro', title: 'Making Governance Worth Participating In', body: 'The chronic problem of DAO governance is apathy. Rational token holders don\'t vote because the individual impact of their vote is low while the cost (time, gas) is real. Solving this requires making governance participation valuable — not just meaningful.' },
          { type: 'text', title: 'Governance Mining', body: 'Some protocols reward governance participation with token distributions. Compound distributes COMP to governance participants. The risk: it incentivizes spam proposals and low-quality voting (vote yes/no randomly to collect rewards). Better model: reward quality participation — proposals that pass, delegate performance metrics, forum contribution scores. Incentivize outcomes, not actions.' },
          { type: 'text', title: 'Delegate Programs', body: 'Paid delegate programs: DAOs pay active, accountable delegates a stipend ($2k-$20k/month). Delegates publish voting rationale for every vote. Delegate performance tracked on scorecards (did they vote? did they publish reasoning? did they participate in forum?). Uniswap, Gitcoin, and Arbitrum all run paid delegate programs. This professionalizes governance participation.' },
          { type: 'highlight', title: 'Governance NFTs and Identity', body: 'Non-transferable governance reputation NFTs: earned through specific contributions, not purchasable. Represent governance track record. Penalize bad behavior (slashing governance reputation for malicious proposals). Weight votes by both token holding AND reputation — hybrid plutocratic/meritocratic governance. Still experimental — Optimism\'s badgeholder system for RetroPGF uses a version of this.' },
          { type: 'text', title: 'Commitment Devices', body: 'Governance participation commitment devices: stake tokens for a period to participate in governance (aligned long-term holders only). Require delegates to have minimum stake. Create "governance bonds" — earn extra rewards by staking governance token + committing to vote for 6 months. These commitment devices filter for participants who take governance seriously vs. tourists.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Governance apathy requires economic solutions. Governance mining incentivizes participation but risks quality. Paid delegate programs professionalize governance. Reputation NFTs add meritocratic weighting. Commitment devices filter serious participants from tourists.' },
        ]},
        { id: 'dao_exp_l5', title: 'The Future of DAOs', slides: [
          { type: 'intro', title: 'Organizations of the Future', body: 'DAOs are a 5-year-old organizational form trying to solve problems that have existed for millennia — collective action, principal-agent conflict, resource allocation, accountability. They\'re producing novel solutions, but the experiments are still early. Here\'s where the frontier is.' },
          { type: 'text', title: 'AI + DAO Integration', body: 'AI agents participating in DAO governance is no longer theoretical. AI systems can: analyze proposals and flag risks, summarize long discussion threads, simulate proposal outcomes, and eventually vote autonomously with defined mandates. a16z\'s "AI-driven DAO" paper explores AI as a governance participant. Key question: who is accountable when an AI agent\'s vote causes harm?' },
          { type: 'text', title: 'Network States', body: 'Balaji Srinivasan\'s "Network State" concept: start online, build community with shared values, eventually acquire land and achieve diplomatic recognition. This extends DAOs from financial coordination to territorial governance. Praxis, Próspera, and other network state experiments are attempting this. DAOs as the organizing structure for sovereign jurisdictions — the most ambitious extension of the concept.' },
          { type: 'highlight', title: 'On-Chain Identity and Reputation', body: 'The missing piece for mature DAO governance: persistent on-chain identity. Soul-Bound Tokens (non-transferable) encode reputation earned through governance participation. Attestations: on-chain credentials that verify real-world claims (EAS — Ethereum Attestation Service). A governance participant\'s full history — every vote, proposal, and contribution — accessible on-chain. This enables reputation-weighted governance that can\'t be gamed by buying tokens.' },
          { type: 'text', title: 'The Coordination Primitive', body: 'Ultimately, DAOs are a new coordination primitive — a way for humans to organize collective action with fewer trust requirements than traditional institutions. They won\'t replace corporations entirely. But for open, global, permissionless coordination around shared resources — financial protocols, open source software, public goods — they may become the standard organizational form. The infrastructure is 5 years old. The experiments are just beginning.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'AI governance participation is emerging. Network States extend DAOs to territorial governance. On-chain identity (SBTs, EAS) will enable meritocratic governance. DAOs are a coordination primitive still in its first generation — the experiments of 2020-2024 will define the design space for decades.' },
        ]},
      ],
      quiz: [
        { id: 'dao_exp_q1', question: 'What is "conviction voting" and how does it address token-weighted voting\'s weaknesses?', options: ['Requiring multiple votes to pass a proposal', 'Voting power accumulates the longer you hold a position — rewarding patient, long-term aligned voters over last-minute whale interventions and vote buying', 'Only allowing staked tokens to vote', 'A system where delegates vote on behalf of small holders'], correct: 1, explanation: 'Conviction voting: the longer a voter holds their vote in a direction, the more power it accumulates. This makes last-minute large whale interventions less effective — you can\'t buy tokens the day of a vote and dominate. Long-term holders with consistent positions accumulate disproportionate conviction, aligning governance power with genuine stakeholders.' },
        { id: 'dao_exp_q2', question: 'Why is ve-tokenomics considered one of the most successful tokenomics innovations in DeFi?', options: ['It makes tokens non-transferable', 'Vote-escrowing concentrates governance in long-term aligned holders, dramatically reduces sell pressure (locked tokens can\'t dump), and creates strong token demand (must lock to access governance rights)', 'It distributes tokens equally to all participants', 'It creates unlimited token supply'], correct: 1, explanation: 've-tokenomics: lock tokens 1-4 years → receive veCRV → get boosted rewards + fee share + governance power. The longer the lock, the more veCRV. This: (1) reduces circulating supply (locked = can\'t sell), (2) aligns governance with long-term holders, (3) creates demand for the token as a governance right. Curve\'s multi-billion dollar ecosystem is testament to this design.' },
        { id: 'dao_exp_q3', question: 'What is the "Labs + DAO" hybrid model used by protocols like Uniswap?', options: ['A co-development agreement between two protocols', 'A company (Labs) handles day-to-day development and product while a DAO governs smart contract upgrades and parameters — combining operational speed with governance legitimacy', 'A legal structure where Labs owns the DAO', 'A funding arrangement where Labs provides venture capital to the DAO'], correct: 1, explanation: 'Uniswap Labs (a company) builds the frontend, protocol improvements, and business development. Uniswap DAO (UNI holders) controls the smart contracts and protocol parameters. Labs provides speed and accountability; DAO provides legitimacy and decentralization. Critics call it decentralization theater; pragmatists call it necessary for early-stage protocols.' },
        { id: 'dao_exp_q4', question: 'What problem do paid delegate programs solve?', options: ['They reduce the cost of on-chain voting', 'They professionalize governance by paying active, accountable participants to vote thoughtfully and publish their reasoning — converting governance from a burden into a viable career path', 'They eliminate the need for token-weighted voting', 'They reduce the number of governance proposals submitted'], correct: 1, explanation: 'Unpaid governance participation has high costs (time, gas) and low individual impact. Paid delegates are incentivized to: vote on every proposal, publish detailed reasoning, participate in forum discussions, and be accountable for their votes. This professionalizes governance and improves decision quality beyond what anonymous, unpaid token holders provide.' },
        { id: 'dao_exp_q5', question: 'How might Soul-Bound Tokens (SBTs) improve DAO governance quality?', options: ['By preventing token transfers and stopping speculation', 'By creating non-transferable, earned governance reputation — enabling governance systems that weight votes by both token holdings AND demonstrated track record, resisting plutocratic capture', 'By replacing governance tokens with identity tokens', 'By making all governance anonymous'], correct: 1, explanation: 'SBTs encode proven contribution history that can\'t be bought. A hybrid governance system (token weight + reputation weight) means buying $10M in tokens doesn\'t give full control — you also need demonstrated governance track record. This resists plutocratic capture while preserving economic alignment of token holders.' },
      ],
    },
  ],
};

export default dao;
